package genxsolution.vms.vmsbackend.maintenance_management.maintenance_program.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program.mapper.MaintenanceProgramMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program.repository.MaintenanceProgramRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceProgramService { private final MaintenanceProgramRepository repository; private final MaintenanceProgramMapper mapper; public MaintenanceProgramService(MaintenanceProgramRepository repository,MaintenanceProgramMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceProgramResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceProgramResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceProgram", String.valueOf(id))); } public MaintenanceProgramResponse create(MaintenanceProgramUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceProgramResponse update(UUID id,MaintenanceProgramUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceProgram", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceProgram", String.valueOf(id)); } }
